// Combina brief, personas y clientes; segmenta y prepara el copy
const allItems = $input.all();
const briefItem    = $('Filtrar Aprobado').first().json;
const personsResp  = allItems[1]?.json || {};
const wonDealsResp = allItems[2]?.json || {};

const persons  = personsResp.data  || [];
const wonDeals = wonDealsResp.data || [];
const brief_md = briefItem.brief_md || '';
const tipo     = briefItem.tipo_campaña || 'T1';

// IDs de clientes (personas con deal ganado)
const clientPersonIds = new Set(wonDeals.map(d => d.person_id?.value).filter(Boolean));

// Personas con email, separadas por segmento
const KEYWORDS = {
  'Manufactura / Nearshoring': ['manufactur','industrial','plant','automotri','aerospace','semiconductor','nearshoring'],
  'Financiero / Fintech':      ['banco','bank','financier','fintech','seguro','credito','pago','afore','inversion'],
  'Retail / CPG':              ['retail','comercio','tienda','supermercado','walmart','oxxo','fmcg','consumer','aliment'],
  'Gobierno':                  ['gobierno','municipal','estado','secretaria','imss','issste','pemex','cfe','federal'],
  'Salud':                     ['hospital','clinica','salud','medic','pharma','laboratori'],
  'Tecnología / IT':           ['tecnolog','software','digital','tech','system','solution','data','cloud'],
  'Telecomunicaciones':        ['telecom','telcel','telmex','at&t','movistar','axtel','megacable'],
  'Transporte / Logística':    ['transport','logistic','carga','cargo','aerolinea'],
  'Energía':                   ['energia','petroleo','gas','electric','solar','eolica']
};

function getSegment(orgName) {
  const n = (orgName || '').toLowerCase();
  for (const [seg, kws] of Object.entries(KEYWORDS)) {
    if (kws.some(kw => n.includes(kw))) return seg;
  }
  return 'Sin clasificar';
}

// Construir lista segmentada con email
const segmented = {};
const allEmailList = [];

persons.forEach(p => {
  const email = p.email?.[0]?.value;
  if (!email) return;
  const orgName = p.org_id?.name || '';
  const seg = getSegment(orgName);
  const isClient = clientPersonIds.has(p.id);
  const contact = {
    id: p.id,
    name: p.name,
    email,
    org: orgName,
    segmento: seg,
    tipo_contacto: isClient ? 'Cliente' : 'Prospecto'
  };
  if (!segmented[seg]) segmented[seg] = { clientes: [], prospectos: [] };
  isClient ? segmented[seg].clientes.push(contact) : segmented[seg].prospectos.push(contact);
  allEmailList.push(contact);
});

// Resumen de segmentación
const segResumen = Object.entries(segmented).map(([seg, data]) => ({
  segmento: seg,
  clientes: data.clientes.length,
  prospectos: data.prospectos.length,
  total: data.clientes.length + data.prospectos.length
})).sort((a, b) => b.total - a.total);

return [{
  json: {
    brief_md,
    tipo_campaña: tipo,
    fecha_corta: briefItem.fecha || new Date().toLocaleDateString('es-MX'),
    segmented,
    segResumen,
    total_campañable: allEmailList.length,
    all_email_list: allEmailList
  }
}];

// Parsea la respuesta de Claude y prepara los datos para crear la campaña
const claudeResp = $input.first().json;
const rawText = claudeResp.content?.[0]?.text || '{}';

let copy;
try {
  const clean = rawText.replace(/^```json\s*/i,'').replace(/```\s*$/,'').trim();
  copy = JSON.parse(clean);
} catch(e) {
  copy = { email: {
    subject: 'Intel Comercial Bambu',
    preheader: '',
    hero_headline: 'Las señales de mercado de esta semana',
    hero_subline: '',
    flash_bullets: [],
    sections: [],
    insight_titulo: '',
    insight_cuerpo: '',
    cta_texto: 'Conversemos',
    cta_url: 'https://bambu-techservices.com/contacto'
  } };
}

const prev = $('Segmentar Contactos').first().json;

return [{
  json: {
    email_copy: copy.email,
    brief_md: prev.brief_md,
    segmented: prev.segmented,
    segResumen: prev.segResumen,
    total_campañable: prev.total_campañable,
    fecha_corta: prev.fecha_corta
  }
}];

const data = $input.first().json;
const rows = data.values || [];
if (rows.length < 2) return [{ json: { found: false } }];

const headers = rows[0];
const estIdx = headers.indexOf('estado');
const fechaIdx = headers.indexOf('fecha');

let found = null;
let foundRowNum = -1;
for (let i = rows.length - 1; i >= 1; i--) {
  if (rows[i][estIdx] === 'aprobado') {
    found = rows[i];
    foundRowNum = i + 1; // 1-based (header=row1, first data=row2)
    break;
  }
}

if (!found) return [{ json: { found: false } }];

const obj = {};
headers.forEach((h, idx) => { obj[h] = found[idx] || ''; });
return [{ json: { ...obj, found: true, _rowNum: foundRowNum } }];

let rowNum = -1;
try { rowNum = $('Filtrar Aprobado').first().json._rowNum || -1; } catch(e) {}
return [{ json: { _rowNum: rowNum } }];

// Prepara los datos para registrar en el Sheet "Campañas"
// Corre después de PD Campaigns (continueOnFail=true)
const pdResult = $input.first().json;
const html = $('Build HTML Email').first().json;

// campaign_id: si Pipedrive devolvió data.id úsalo, si falló queda 'pendiente'
const campaignId = String(
  pdResult?.data?.id || pdResult?.id || 'pendiente'
);

return [{
  json: {
    fecha_creacion: html.fecha_corta || '',
    campaign_id: campaignId,
    nombre: 'Intel Bambu — ' + (html.fecha_corta || ''),
    template: 'T1',
    total_campañable: String(html.total_campañable || 0),
    segmentos_json: JSON.stringify(html.segResumen || {}),
    estado: 'creada_borrador',
    opens: '0',
    clicks: '0',
    hot_signals: '0'
  }
}];

